// Mapa SIGLA -> Cidade/Regional
const SIGLA_CIDADE = {
  IAI:'Itajaí', SOO:'São José', CAS:'Campinas', PAE:'Porto Alegre', CTA:'Curitiba',
  GNA:'Goiânia', SRR:'S.J. Rio Preto', RBP:'Ribeirão Preto', JLE:'Joinville',
  BQE:'Brusque', PMJ:'Palmas', JGS:'Jaraguá do Sul', LGS:'Lages', BNU:'Blumenau',
  CCO:'Chapecó', BSB:'Brasília', SPO:'São Paulo', BHE:'Belo Horizonte', ITP:'Itapema'
};
// Supervisor -> regionais
const SUPERVISORES = {
  'Átilas Souza':   ['ITP','SOO','PAE','CCO','LGS'],
  'Alexandre Reis': ['CTA','JLE','IAI','BNU','BQE','JGS'],
  'Rodrigo Lodo':   ['CAS','SRR','RBP','PMJ','GNA','BSB','SPO','BHE']
};
function siglaSupervisor(sig){
  for(const sup in SUPERVISORES){ if(SUPERVISORES[sup].includes(sig)) return sup; }
  return '';
}
// Contas ativas por sigla (a partir da planilha Contas x EPV)
let CONTAS_POR_SIGLA = {};
let CONTAS_TOTAL = 0;
function recomputeContas(){
  CONTAS_POR_SIGLA={}; CONTAS_TOTAL=0;
  EMBED_CONTAS.forEach(c=>{
    if(!CONTAS_POR_SIGLA[c.sigla]) CONTAS_POR_SIGLA[c.sigla]=0;
    CONTAS_POR_SIGLA[c.sigla]+=c.contas; CONTAS_TOTAL+=c.contas;
  });
}
recomputeContas();
Promise.all([
  fetch('/api/controle-os').then(r=>r.json()),
  fetch('/api/base').then(r=>r.json()).catch(()=>[])
])
.then(([data, baseData])=>{
  // Se a base compartilhada foi carregada, substitui o EMBED_CONTAS hard-coded
  if(baseData && baseData.length){
    EMBED_CONTAS = baseData.map(row=>({
      sigla: (String(row['TecnicoResponsavel']||'')).split(' - ')[1]?.trim()||'',
      tecnico: String(row['TecnicoResponsavel']||''),
      contas: Number(row['#Contas'])||0
    })).filter(c=>c.sigla);
    recomputeContas();
  }

  if(!Array.isArray(data)||!data.length){
    const m=document.getElementById('metaInfo');
    if(m)m.innerHTML='<span style="color:#e08c00">⚠ Sem dados carregados</span>';
    toast('Nenhum dado encontrado. Faça upload em /upload.','err');
    return;
  }

  rawData = data.map(norm).filter(Boolean);
  buildSupervisorCards();
  setupFilters();
  loadState();
  applyFilters();

  fetch('/api/meta/controle-os')
  .then(r=>r.json())
  .then(meta=>{
    const m=document.getElementById('metaInfo');
    if(m&&meta&&meta.atualizado_em){
      m.innerHTML =
        '<strong>'+(meta.registros||0).toLocaleString('pt-BR')+' O.S total</strong><br>'+
        'Atualizado em '+meta.atualizado_em+'<br>'+
        '<span style="font-size:10px">'+(meta.arquivo||'')+'</span>';
    }
    checkFreshness(meta);
  })
  .catch(()=>{});

  toast('✓ '+rawData.length.toLocaleString('pt-BR')+' O.S carregadas','ok');
})
.catch(err=>{
  const m=document.getElementById('metaInfo');
  if(m)m.innerHTML='<span style="color:#e05050">✗ Erro ao carregar</span>';
  toast('Erro ao carregar dados.','err');
  console.error(err);
});
// ── FRESHNESS — usa a data do último upload (meta), não os dados ──────────────
function checkFreshness(meta){
  const badge = document.getElementById('xlsxStatus');
  if(!badge) return;
  if(!meta || !meta.atualizado_em){ badge.style.display = 'none'; return; }

  // atualizado_em vem como "DD/MM/YYYY HH:MM"
  const m = meta.atualizado_em.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
  if(!m){ badge.style.display = 'none'; return; }

  const uploadDate = new Date(+m[3], +m[2]-1, +m[1]);
  const hoje = new Date();
  hoje.setHours(0,0,0,0);
  uploadDate.setHours(0,0,0,0);

  const diff = Math.floor((hoje - uploadDate) / (1000*60*60*24));
  const dtStr = uploadDate.toLocaleDateString('pt-BR', {
    day:'2-digit',
    month:'2-digit',
    year:'numeric'
  });

  badge.style.display = 'inline-block';

  if(diff === 0){
    badge.style.background = '#2db86a';
    badge.style.color = '#fff';
    badge.textContent = '✓ Atualizado hoje';
  } else if(diff <= 1){
    badge.style.background = '#2db86a';
    badge.style.color = '#fff';
    badge.textContent = '✓ Atualizado ontem';
  } else if(diff <= 3){
    badge.style.background = '#e08c00';
    badge.style.color = '#fff';
    badge.textContent = `⚠ ${diff}d sem atualizar (${dtStr})`;
  } else {
    badge.style.background = '#e05050';
    badge.style.color = '#fff';
    badge.textContent = `✗ Desatualizado — ${diff}d (${dtStr})`;
  }
}
// STATE
let rawData=[],filteredData=[];
let activeBucket='',activeMotivo='',activeEspec='',activeSupervisor='';
let activeTiposOS = new Set();
const sel={regiao:new Set(),cidade:new Set(),tipo:new Set()};

const BKEYS=['0-2','3-14','15+'];
const BLABELS=['0-2 dias','3-14 dias','+14 dias'];
const BCOLORS={'0-2':'#2db86a','3-14':'#4d9fdd','15+':'#e05050'};
const MCOLORS=['#005BAC','#F5B400','#2db86a','#e05050','#8b5cf6','#0ea5e9'];

let bucketChart,motivoChart;

// ===== INICIALIZAÇÃO (sem fetch) =====
function init(){
  const data = EMBED_OS;
  rawData = data.map(norm).filter(Boolean);
  activeBucket=''; activeMotivo='';
  sel.regiao.clear(); sel.cidade.clear(); sel.tipo.clear();
  buildSupervisorCards();
  setupFilters();
  loadState();
  applyFilters();
  const m=document.getElementById('metaInfo');
  if(m) m.innerHTML='<strong>'+rawData.length.toLocaleString('pt-BR')+' O.S'+
    ' · '+CONTAS_TOTAL.toLocaleString('pt-BR')+' Contas Ativas</strong>';
  toast('✓ '+rawData.length.toLocaleString('pt-BR')+' registros carregados','ok');
}

function norm(r){
  const tipoOsMap = {
    'Nova instalação':'Instalação','A365 Reativação Contratual':'Instalação',
    'A365 Repareamento':'Instalação','A365 Troca de Tecnologia':'Instalação',
    'A365 Manutenção Técnica':'Manutenção','A365 Intrusão':'Manutenção',
    'A365 Reentrega':'Manutenção','A365 Remanejar Equipamento':'Manutenção',
    'A365 Mudança de Endereço':'Manutenção','A365 Atendimento Impedido':'Manutenção',
    'A365 Colagem de Placa':'Manutenção',
    'Falha de comunicação de dispositivo':'Manutenção Remota',
    'Falha de comunicação de central':'Manutenção Remota',
    'A365 - Cancelamento por Inadimplência':'Administrativa',
    'A365 Retirada de Equipamentos':'Desinstalação',
    'A365 Troca de Titularidade':'Desinstalação','Cancelamento de contrato':'Desinstalação',
    'A365 Administrativa de Apoio':'Administrativa'
  };
  const tipoOS = tipoOsMap[r['Defeito']] ?? 'Manutenção';
  const os = String(r['Nº OS']||'').toUpperCase();
  if(os && os.includes('AVERAGE')) return null;
  const tech = String(r['Téc. Executor']||'').trim();
  const dias = (function(v){
    if(v==null) return 0;
    if(typeof v==='number') return Math.trunc(v);
    let s=String(v).trim().replace(',', '.');
    const f=parseFloat(s.replace(/[^0-9.\-]/g,''));
    return isNaN(f)?0:Math.trunc(f);
  })(r['Dias'] ?? r['# Dias (Bruto)']);
  let b='0-2';
  if(dias<=2) b='0-2'; else if(dias<=14) b='3-14'; else b='15+';
  // SIGLA: segundo token de Téc. Executor (corrige base que vinha vazia em Regional)
  const p=tech.split('-').map(x=>x.trim());
  let sig = String(r['Sigla']||'').trim(); if(!sig) sig = p[1]||'';
  const tipoTec = (p[2]||'').toUpperCase();        // EPV ou PJ
  const nomeTec = p.length>3 ? p.slice(3).join(' - ') : (p[p.length-1]||'');
  const cidadeReg = SIGLA_CIDADE[sig] || sig;
  return {
    'Nº OS': r['Nº OS'] ?? '',
    'Téc. Executor': tech,
    'Sigla': sig,
    'Nome': nomeTec,
    'Tipo': tipoTec,
    'Cidade': r['Cidade'] ?? '',
    'Regional': sig,              // regional = sigla
    'RegionalNome': cidadeReg,
    'Supervisor': siglaSupervisor(sig),
    'Defeito': r['Defeito'] ?? '',
    '# Dias (Bruto)': dias,
    'Bucket': b,
    'Abertura': r['Abertura'] ?? '',
    'Agendamento': r['Agendamento'] ?? '',
    'Pausada?': r['Pausada?'] ?? '',
    'Mot. Pausa': r['Mot. Pausa'] ?? '',
    'Fantasia': r['Fantasia'] ?? '',
    'Conta': r['Conta'] ?? '',
    'TipoOS': tipoOS,
  };
}

// ===== CARDS DE SUPERVISOR =====
function buildSupervisorCards(){
  const host=document.getElementById('supCards');
  if(!host) return;
  const ordem=['Alexandre Reis','Rodrigo Lodo','Átilas Souza'];
  host.innerHTML = ordem.map(sup=>{
    const regs=SUPERVISORES[sup];
    const osCnt=rawData.filter(r=>r['Supervisor']===sup).length;
    const contas=regs.reduce((a,s)=>a+(CONTAS_POR_SIGLA[s]||0),0);
    const pct = contas>0 ? ((osCnt/contas)*100).toFixed(1).replace('.',',')+'%' : '—';
    return `<div class="supcard" data-sup="${esc(sup)}">
      <div class="supname">${esc(sup)}</div>
      <div class="supregs">${regs.join(' · ')}</div>
      <div class="supstats"><span><b>${osCnt.toLocaleString('pt-BR')}</b> OS</span><span><b>${contas.toLocaleString('pt-BR')}</b> contas</span><span><b>${pct}</b> O.S/conta</span></div>
    </div>`;
  }).join('');
  host.querySelectorAll('.supcard').forEach(c=>c.addEventListener('click',()=>{
    const sup=c.dataset.sup;
    activeSupervisor = activeSupervisor===sup ? '' : sup;
    // limpa filtro de região manual ao trocar de supervisor
    sel.regiao.clear(); sel.cidade.clear();
    setupFilters();
    applyFilters();
  }));
}

// regionais válidas conforme supervisor ativo
function regionaisPermitidas(){
  if(activeSupervisor) return new Set(SUPERVISORES[activeSupervisor]);
  return null; // todas
}

// MULTISELECT
function uniq(key){
  const perm=regionaisPermitidas();
  let src=rawData;
  if(perm) src=src.filter(r=>perm.has(r['Regional']));
  return[...new Set(src.map(x=>x[key]).filter(Boolean))].sort((a,b)=>String(a).localeCompare(String(b),'pt-BR'));
}

function buildMs(id,key,placeholder){
  const wrap=document.getElementById('ms-'+id);
  const btn=wrap.querySelector('.ms-btn');
  const dd=document.getElementById('dd-'+id);
  const srch=document.getElementById('srch-'+id);
  const itemsEl=document.getElementById('items-'+id);
  const allEl=document.getElementById('all-'+id);
  const cbAll=document.getElementById('cb-all-'+id);
  const cnt=document.getElementById('cnt-'+id);
  const tags=document.getElementById('tags-'+id);
  const set=sel[id];
  function renderItems(filter=''){
    const vals=uniq(key);
    itemsEl.innerHTML='';
    vals.filter(v=>v.toLowerCase().includes(filter.toLowerCase())).forEach(v=>{
      const div=document.createElement('div');
      div.className='ms-item'+(set.has(v)?' checked':'');
      const lbl = id==='regiao' ? (v+' — '+(SIGLA_CIDADE[v]||v)) : v;
      div.innerHTML=`<div class="ms-cb"></div><span class="ms-label" title="${esc(lbl)}">${esc(lbl)}</span>`;
      div.addEventListener('click',()=>{
        if(set.has(v))set.delete(v);else set.add(v);
        div.classList.toggle('checked',set.has(v));
        updateBtn();applyFilters();
      });
      itemsEl.appendChild(div);
    });
    const allSelected=vals.length>0&&vals.every(v=>set.has(v));
    cbAll.style.background=allSelected?'var(--blue)':'';
    cbAll.style.borderColor=allSelected?'var(--blue)':'';
    cbAll.innerHTML=allSelected?'<span style="display:flex;align-items:center;justify-content:center;width:100%;height:100%"><svg width="9" height="7" viewBox="0 0 10 8" fill="none"><path d="M1 4L3.5 6.5L9 1" stroke="white" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/></svg></span>':'<span></span>';
  }
  function updateBtn(){
    const text=btn.querySelector('.ms-text');
    if(set.size===0){text.textContent=placeholder;cnt.classList.add('hidden');}
    else{text.textContent=`${set.size} selecionado${set.size>1?'s':''}`;cnt.textContent=set.size;cnt.classList.remove('hidden');}
    tags.innerHTML=[...set].map(v=>`<div class="atag" data-v="${esc(v)}"><span title="${esc(v)}">${esc(v.length>20?v.slice(0,18)+'…':v)}</span><span class="atag-x" data-id="${id}" data-v="${esc(v)}">×</span></div>`).join('');
    tags.querySelectorAll('.atag-x').forEach(x=>x.addEventListener('click',e=>{
      e.stopPropagation();set.delete(x.dataset.v);updateBtn();applyFilters();renderItems(srch.value);
    }));
  }
  allEl.addEventListener('click',()=>{
    const vals=uniq(key);
    if(vals.every(v=>set.has(v))){set.clear();}else{vals.forEach(v=>set.add(v));}
    renderItems(srch.value);updateBtn();applyFilters();
  });
  btn.addEventListener('click',e=>{
    e.stopPropagation();
    const wasOpen=dd.classList.contains('show');
    document.querySelectorAll('.ms-dropdown.show').forEach(d=>d.classList.remove('show'));
    document.querySelectorAll('.ms-btn.open').forEach(b=>b.classList.remove('open'));
    if(!wasOpen){dd.classList.add('show');btn.classList.add('open');srch.focus();renderItems();}
  });
  srch.addEventListener('input',()=>renderItems(srch.value));
  document.addEventListener('click',e=>{if(!wrap.contains(e.target)){dd.classList.remove('show');btn.classList.remove('open');}});
  return{render:renderItems,update:updateBtn};
}

const msRegiao=buildMs('regiao','Regional','Todas as regiões');
const msCidade=buildMs('cidade','Cidade','Todas as cidades');
const msTipo=buildMs('tipo','Defeito','Todos os motivos');

function setupFilters(){
  msRegiao.render();msRegiao.update();
  msCidade.render();msCidade.update();
  msTipo.render();msTipo.update();
}

function applyFilters(){
  const perm=regionaisPermitidas();
  filteredData=rawData.filter(r=>{
    const supOk=!perm||perm.has(r['Regional']);
    const bOk=!activeBucket||r['Bucket']===activeBucket;
    const mOk=!activeMotivo||r['Defeito']===activeMotivo;
    const eOk=!activeEspec||r['Téc. Executor']===activeEspec;
    const rOk=sel.regiao.size===0||sel.regiao.has(r['Regional']);
    const cOk=sel.cidade.size===0||sel.cidade.has(r['Cidade']);
    const tOk=sel.tipo.size===0||sel.tipo.has(r['Defeito']);
    const tosOk=activeTiposOS.size===0||activeTiposOS.has(r['TipoOS']);
    return supOk&&bOk&&mOk&&eOk&&rOk&&cOk&&tOk&&tosOk;
  });
  updateSupCardsUI();
  updateFilterUI();renderAll();saveState();
}

function updateSupCardsUI(){
  document.querySelectorAll('.supcard').forEach(c=>{
    c.classList.toggle('active', c.dataset.sup===activeSupervisor);
  });
  const back=document.getElementById('backOverview');
  if(back) back.style.display = activeSupervisor ? 'inline-flex':'none';
  const ttl=document.getElementById('viewTitle');
  if(ttl) ttl.textContent = activeSupervisor ? ('Supervisor: '+activeSupervisor) : 'Visão Geral';
}

function updateFilterUI(){
  const ind=document.getElementById('filterIndicator');
  const lbl=document.getElementById('filterLabel');
  const dot=document.getElementById('filterDot');
  document.querySelectorAll('.bpill').forEach(p=>p.classList.toggle('active',p.dataset.b===activeBucket));
  document.querySelectorAll('.kpi[data-bucket]').forEach(k=>{
    const b=k.dataset.bucket;
    k.classList.toggle('active-kpi',activeBucket!==''&&b===activeBucket);
  });
  const hasExtra=activeBucket||activeMotivo||activeEspec;
  if(hasExtra){
    ind.classList.add('show');
    const parts=[];
    if(activeBucket){parts.push(activeBucket);dot.style.background=BCOLORS[activeBucket]||'var(--blue)';}
    if(activeMotivo){parts.push(activeMotivo);}
    if(activeEspec){parts.push(activeEspec);}
    lbl.textContent=`Filtrando: ${parts.join(' · ')} · ${filteredData.length.toLocaleString('pt-BR')} OS`;
  }else{ind.classList.remove('show');}
}

function animN(el,t){if(!el)return;const s=+(el.dataset.v||0),t0=performance.now();const go=n=>{const p=Math.min((n-t0)/500,1),e=1-Math.pow(1-p,3);el.textContent=Math.round(s+(t-s)*e).toLocaleString('pt-BR');if(p<1)requestAnimationFrame(go);};el.dataset.v=t;requestAnimationFrame(go);}
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function dark(){return document.documentElement.getAttribute('data-theme')!=='light';}

function renderKPIs(){
  const bc={'0-2':0,'3-14':0,'15+':0};
  document.getElementById('headerCount').textContent=filteredData.length.toLocaleString('pt-BR')+' OS';
  // contadores dos botões TipoOS (escopo supervisor)
  const perm=regionaisPermitidas();
  const escopo = perm ? rawData.filter(r=>perm.has(r['Regional'])) : rawData;
  ['Instalação','Manutenção','Desinstalação','Administrativa'].forEach(t=>{
    const btn=document.querySelector('.tos-btn[data-tos="'+t+'"]'); if(!btn)return;
    const c=escopo.filter(r=>r['TipoOS']===t).length;
    const icon=t==='Instalação'?'📦':t==='Manutenção'?'🔧':t==='Administrativa'?'✏️':'🗑️';
    btn.innerHTML=`${icon} ${t} <span style="opacity:.7;font-weight:400">(${c})</span>`;
  });
  const base=escopo.filter(r=>(!activeEspec||r['Téc. Executor']===activeEspec)&&(sel.regiao.size===0||sel.regiao.has(r['Regional']))&&(sel.cidade.size===0||sel.cidade.has(r['Cidade']))&&(sel.tipo.size===0||sel.tipo.has(r['Defeito']))&&(activeTiposOS.size===0||activeTiposOS.has(r['TipoOS'])));
  base.forEach(r=>bc[r['Bucket']]++);
  // Contas ativas da seleção
  let contasSel;
  if(perm){ contasSel=[...perm].reduce((a,s)=>a+(CONTAS_POR_SIGLA[s]||0),0); }
  else { contasSel=CONTAS_TOTAL; }
  if(sel.regiao.size>0){ contasSel=[...sel.regiao].reduce((a,s)=>a+(CONTAS_POR_SIGLA[s]||0),0); }
  animN(document.getElementById('kpiTotal'),filteredData.length);
  animN(document.getElementById('kpi31'),bc['15+']);
  animN(document.getElementById('kpiContas'),contasSel);
  animN(document.getElementById('kpiTechs'),new Set(filteredData.map(r=>r['Téc. Executor']).filter(Boolean)).size);
  // % OS / Conta
  const pctEl=document.getElementById('kpiPct');
  if(pctEl){ pctEl.textContent = contasSel>0 ? ((filteredData.length/contasSel)*100).toFixed(1).replace('.',',')+'%' : '—'; }
  const pctSub=document.getElementById('kpiPctSub');
  if(pctSub){ pctSub.textContent = filteredData.length.toLocaleString('pt-BR')+' O.S ÷ '+contasSel.toLocaleString('pt-BR'); }
}

function renderTable(){
  const m=new Map();
  filteredData.forEach(r=>{const k=r['Téc. Executor']||'—';if(!m.has(k))m.set(k,{t:k,c:0,s:r['Sigla']||''});m.get(k).c++;});
  const rows=[...m.values()].sort((a,b)=>b.c-a.c);
  document.getElementById('techPill').textContent=rows.length+' técnico'+(rows.length!==1?'s':'');
  const max=rows[0]?.c||1;
  if(!rows.length){document.getElementById('techBody').innerHTML=`<tr><td colspan="4"><div class="emp"><svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="12" cy="12" r="10"/></svg>Sem resultados</div></td></tr>`;return;}
  document.getElementById('techBody').innerHTML=rows.map((r,i)=>{
    const rc=i===0?'r1':i===1?'r2':i===2?'r3':'';
    const isAct=activeEspec===r.t;
    return`<tr class="${isAct?'espec-active':''}" data-espec="${esc(r.t)}" title="Clique para filtrar por ${esc(r.t)}"><td><span class="rk ${rc}">${i+1}</span></td><td title="${esc(r.t)}">${esc(r.t)}<span class="bari" style="width:${Math.round((r.c/max)*60)}px"></span></td><td>${r.c}</td><td><span class="stag">${esc(r.s)}</span></td></tr>`;
  }).join('');
}

function renderOS(){
  document.getElementById('osPill').textContent=filteredData.length.toLocaleString('pt-BR');
  const items=filteredData.slice(0,Math.max(100,filteredData.length));
  document.getElementById('osList').innerHTML=items.length
    ?items.map(r=>{const v=String(r['Nº OS']);return `<div class="osc" data-os="${v}">${esc(v)}</div>`;}).join('')
    :`<div style="grid-column:1/-1" class="emp"><svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/></svg>Sem dados</div>`;
}

function renderBucket(){
  const perm=regionaisPermitidas();
  let base=perm?rawData.filter(r=>perm.has(r['Regional'])):rawData;
  base=base.filter(r=>(!activeMotivo||r['Defeito']===activeMotivo)&&(!activeEspec||r['Téc. Executor']===activeEspec)&&(sel.regiao.size===0||sel.regiao.has(r['Regional']))&&(sel.cidade.size===0||sel.cidade.has(r['Cidade']))&&(sel.tipo.size===0||sel.tipo.has(r['Defeito']))&&(activeTiposOS.size===0||activeTiposOS.has(r['TipoOS'])));
  const cnt={'0-2':0,'3-14':0,'15+':0};
  base.forEach(r=>cnt[r['Bucket']]++);
  const vals=BKEYS.map(k=>cnt[k]);
  const tot=vals.reduce((a,b)=>a+b,0)||1;
  const tc=dark()?'#7a8aa0':'#5a6e8a';
  const gc=dark()?'rgba(255,255,255,.05)':'rgba(0,91,172,.06)';
  const bgColors=BKEYS.map(k=>{const hex=BCOLORS[k];const a=activeBucket===''||activeBucket===k?1:.35;return a<1?hex+Math.round(a*255).toString(16).padStart(2,'0'):hex;});
  if(typeof Chart==="undefined"){document.getElementById("bucketChart").parentElement.innerHTML="<div class=\"emp\">Gráfico indisponível</div>";return;}if(bucketChart)bucketChart.destroy();
  bucketChart=new Chart(document.getElementById('bucketChart'),{
    type:'bar',
    data:{labels:BLABELS,datasets:[{data:vals,backgroundColor:bgColors,borderRadius:7,borderSkipped:false}]},
    options:{responsive:true,maintainAspectRatio:false,
      onClick:(e,els)=>{if(!els.length)return;const b=BKEYS[els[0].index];activeBucket=activeBucket===b?'':b;applyFilters();},
      plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>` ${ctx.raw.toLocaleString('pt-BR')} OS (${((ctx.raw/tot)*100).toFixed(1)}%)`}}},
      scales:{x:{grid:{display:false},ticks:{color:tc,font:{weight:'700',size:12}},border:{display:false}},y:{beginAtZero:true,suggestedMax:Math.max(...vals,1)*1.18,grid:{color:gc},ticks:{color:tc},border:{display:false}}},
      layout:{padding:{top:18}},
      animation:{duration:300}},
    plugins:[{id:'lbl',afterDatasetsDraw(ch){const{ctx}=ch;ctx.save();ctx.font='700 12px Inter';ctx.textAlign='center';ctx.fillStyle=dark()?'#b0bfcf':'#5a6e8a';const top=ch.chartArea.top;ch.getDatasetMeta(0).data.forEach((b,i)=>{if(vals[i]>0){const txt=vals[i].toLocaleString('pt-BR')+' · '+((vals[i]/tot)*100).toFixed(0)+'%';let y=b.y-8;if(y<top+10){y=b.y+18;ctx.fillStyle='#fff';}else{ctx.fillStyle=dark()?'#b0bfcf':'#5a6e8a';}ctx.fillText(txt,b.x,y);}});ctx.restore();}}]
  });
  document.getElementById('bucketChart').style.cursor='pointer';
}

const _motivoColorMap={};let _motivoColorCounter=0;
function MOTIVO_COLOR_IDX(label){if(!(_motivoColorMap.hasOwnProperty(label))){_motivoColorMap[label]=_motivoColorCounter++;}return _motivoColorMap[label];}
function renderMotivo(){
  const TIPOS=['Instalação','Manutenção','Manutenção Remota','Desinstalação','Administrativa'];
  const TCOLORS={'Instalação':'#2db86a','Manutenção':'#4d9fdd','Manutenção Remota':'#005BAC','Desinstalação':'#e05050','Administrativa':'#8b5cf6'};
  const cnt={};filteredData.forEach(r=>{const t=r['TipoOS']||'Outros';cnt[t]=(cnt[t]||0)+1;});
  const dados=TIPOS.filter(t=>cnt[t]).map(t=>[t,cnt[t]]);
  const total=dados.reduce((a,[,v])=>a+v,0)||1;

  function toggleTipo(t){
    if(activeTiposOS.has(t))activeTiposOS.delete(t);else activeTiposOS.add(t);
    document.querySelectorAll('.tos-btn').forEach(b=>b.classList.toggle('tos-active',activeTiposOS.has(b.dataset.tos)));
    applyFilters();
  }

  // ---- legenda HTML customizada (valor + %) ----
  const lg=document.getElementById('tipoLegend');
  if(lg){
    lg.innerHTML=dados.map(([k,v])=>{
      const pct=((v/total)*100).toFixed(1).replace('.',',');
      const dim=(activeTiposOS.size>0&&!activeTiposOS.has(k))?' dim':'';
      return `<div class="lg-item${dim}" data-tipo="${esc(k)}">
        <span class="lg-dot" style="background:${TCOLORS[k]||'#7a8aa0'}"></span>
        <span class="lg-name">${esc(k)}</span>
        <span class="lg-val">${v.toLocaleString('pt-BR')}</span>
        <span class="lg-pct">${pct}%</span>
      </div>`;
    }).join('');
    lg.querySelectorAll('.lg-item').forEach(it=>it.addEventListener('click',()=>toggleTipo(it.dataset.tipo)));
  }

  if(typeof Chart==="undefined"){const c=document.getElementById("motivoChart");if(c)c.parentElement.innerHTML="<div class=\"emp\">Gráfico indisponível</div>";return;}
  if(motivoChart)motivoChart.destroy();
  if(!dados.length){motivoChart=null;return;}
  motivoChart=new Chart(document.getElementById('motivoChart'),{
    type:'doughnut',
    data:{labels:dados.map(([k])=>k),datasets:[{data:dados.map(([,v])=>v),backgroundColor:dados.map(([k])=>{const hex=TCOLORS[k]||'#7a8aa0';const a=(activeTiposOS.size===0||activeTiposOS.has(k))?1:.4;return a<1?hex+Math.round(a*255).toString(16).padStart(2,'0'):hex;}),borderWidth:2,borderColor:dark()?'#161d2a':'#fff',hoverOffset:8}]},
    options:{responsive:true,maintainAspectRatio:false,cutout:'62%',
      onClick:(e,els)=>{if(!els.length)return;toggleTipo(dados[els[0].index][0]);},
      plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>` ${ctx.raw.toLocaleString('pt-BR')} OS (${((ctx.raw/total)*100).toFixed(1)}%)`}}},
      animation:{duration:300}}
  });
  document.getElementById('motivoChart').style.cursor='pointer';
}
// Barras horizontais: OS por Regional
function renderRegional(){
  const host=document.getElementById('regList');
  if(!host) return;
  const m=new Map();
  filteredData.forEach(r=>{
    const sig=r['Regional']||'—';
    if(!m.has(sig)) m.set(sig,{sig,c:0,cidades:{}});
    const o=m.get(sig); o.c++;
    const cid=r['Cidade']||'—'; o.cidades[cid]=(o.cidades[cid]||0)+1;
  });
  const rows=[...m.values()].sort((a,b)=>b.c-a.c);
  if(!rows.length){host.innerHTML=`<div class="emp">Sem dados</div>`;return;}
  const max=rows[0].c||1;
  host.innerHTML=rows.map(o=>{
    const contas=CONTAS_POR_SIGLA[o.sig]||0;
    const pct = contas>0 ? ((o.c/contas)*100).toFixed(1)+'%' : null;
    const topCid=Object.entries(o.cidades).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([c,n])=>`${c} (${n})`).join(' · ');
    const w=Math.max(4,Math.round((o.c/max)*100));
    return `<div class="regrow">
      <div class="reghead">
        <span class="regname">${esc(o.sig)} <span class="regcity">${esc(SIGLA_CIDADE[o.sig]||'')}</span></span>
        <span class="regval">${o.c.toLocaleString('pt-BR')} OS${pct?` · <span class="regpct" title="OS por conta">${pct} O.S/conta</span>`:''}</span>
      </div>
      <div class="regbar-track"><div class="regbar-fill" style="width:${w}%"></div></div>
      <div class="regcid">${esc(topCid)}</div>
    </div>`;
  }).join('');
}

function toggleTipoOS(t){
  if(activeTiposOS.has(t)) activeTiposOS.delete(t); else activeTiposOS.add(t);
  document.querySelectorAll('.tos-btn').forEach(btn=>{btn.classList.toggle('tos-active',activeTiposOS.has(btn.dataset.tos));});
  applyFilters();
}

// ── LOCALSTORAGE ──
const LS_KEY='bi_a365_state';
function saveState(){try{localStorage.setItem(LS_KEY,JSON.stringify({tema:document.documentElement.getAttribute('data-theme')||'dark',bucket:activeBucket,motivo:activeMotivo,supervisor:activeSupervisor,regiao:[...sel.regiao],cidade:[...sel.cidade],tipo:[...sel.tipo]}));}catch(e){}}
function loadState(){try{const s=JSON.parse(localStorage.getItem(LS_KEY));if(!s)return;
  if(s.tema){document.documentElement.setAttribute('data-theme',s.tema);const btn=document.getElementById('themeToggle');if(btn)btn.innerHTML=s.tema==='light'?`<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>`:`<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>`;}
  activeBucket=s.bucket||'';activeMotivo=s.motivo||'';activeSupervisor=s.supervisor||'';
  if(Array.isArray(s.regiao))s.regiao.forEach(v=>sel.regiao.add(v));
  if(Array.isArray(s.cidade))s.cidade.forEach(v=>sel.cidade.add(v));
  if(Array.isArray(s.tipo))s.tipo.forEach(v=>sel.tipo.add(v));
}catch(e){}}

function safe(fn){try{fn();}catch(e){console.error(fn.name,e);}}function renderAll(){safe(renderKPIs);safe(renderTable);safe(renderOS);safe(renderBucket);safe(renderMotivo);safe(renderRegional);}

// Clique técnico
document.getElementById('techBody').addEventListener('click',(e)=>{const tr=e.target.closest('tr[data-espec]');if(!tr)return;const espec=tr.dataset.espec;activeEspec=activeEspec===espec?'':espec;applyFilters();});
// KPI click (só os com bucket)
document.querySelectorAll('.kpi[data-bucket]').forEach(card=>{card.addEventListener('click',()=>{const b=card.dataset.bucket;if(b==='')return;activeBucket=activeBucket===b?'':b;applyFilters();});});
// Bucket pills
document.querySelectorAll('.bpill').forEach(p=>p.addEventListener('click',()=>{activeBucket=activeBucket===p.dataset.b?'':p.dataset.b;applyFilters();}));
// Clear bucket
document.getElementById('clearBucketBtn').addEventListener('click',()=>{activeBucket='';activeMotivo='';activeEspec='';applyFilters();});
// Voltar à visão geral
document.getElementById('backOverview').addEventListener('click',()=>{activeSupervisor='';sel.regiao.clear();sel.cidade.clear();setupFilters();applyFilters();});
// Reset
document.getElementById('resetBtn').addEventListener('click',()=>{activeBucket='';activeMotivo='';activeEspec='';activeSupervisor='';activeTiposOS.clear();document.querySelectorAll('.tos-btn').forEach(b=>b.classList.remove('tos-active'));sel.regiao.clear();sel.cidade.clear();sel.tipo.clear();setupFilters();applyFilters();saveState();});
// Export
document.getElementById('exportBtn').addEventListener('click',()=>{
  if(!filteredData.length){toast('Nenhum dado para exportar.','err');return;}
  const h=['Nº OS','Nome','Tipo','Regional','Supervisor','Cidade','Defeito','TipoOS','# Dias (Bruto)','Abertura','Agendamento','Pausada?','Mot. Pausa','Fantasia','Conta'];
  const lines=[h.join(';')];
  filteredData.forEach(r=>lines.push(h.map(k=>`"${String(r[k]??'').replace(/"/g,'""')}"`).join(';')));
  const blob=new Blob(['\uFEFF'+lines.join('\n')],{type:'text/csv;charset=utf-8;'});
  const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='os-filtradas.csv';a.click();URL.revokeObjectURL(a.href);
  toast(`✓ ${filteredData.length.toLocaleString('pt-BR')} registros exportados`,'ok');
});
// Theme
document.getElementById('themeToggle').addEventListener('click',()=>{
  const root=document.documentElement;const next=root.getAttribute('data-theme')==='dark'?'light':'dark';root.setAttribute('data-theme',next);
  document.getElementById('themeToggle').innerHTML=next==='light'?`<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>`:`<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>`;
  if(filteredData.length){renderBucket();renderMotivo();}
  saveState();
});

// Sidebar collapse
const _layoutEl=document.querySelector('.layout');
function setSidebar(collapsed){
  _layoutEl.classList.toggle('collapsed',collapsed);
  try{localStorage.setItem('bi_a365_sidebar',collapsed?'1':'0');}catch(e){}
}
document.getElementById('sidebarToggle').addEventListener('click',()=>{ setSidebar(!_layoutEl.classList.contains('collapsed')); });
try{ if(localStorage.getItem('bi_a365_sidebar')==='1') setSidebar(true); }catch(e){}
function toast(msg,type){const t=document.getElementById('toast');t.textContent=msg;t.className=`show ${type}`;clearTimeout(t._t);t._t=setTimeout(()=>{t.className='';},3200);}
// Copiar OS
document.getElementById('osList').addEventListener('click',function(e){
  const card=e.target.closest('.osc');if(!card)return;
  const val=card.getAttribute('data-os')||card.textContent.trim();
  const ta=document.createElement('textarea');ta.value=val;ta.style.cssText='position:fixed;top:0;left:0;opacity:0;pointer-events:none;';
  document.body.appendChild(ta);ta.focus();ta.select();let ok=false;try{ok=document.execCommand('copy');}catch(err){}document.body.removeChild(ta);
  if(ok){card.classList.add('copied');toast('OS '+val+' copiada!','ok');setTimeout(()=>card.classList.remove('copied'),1200);}
  else if(navigator.clipboard){navigator.clipboard.writeText(val).then(()=>{card.classList.add('copied');toast('OS '+val+' copiada!','ok');setTimeout(()=>card.classList.remove('copied'),1200);}).catch(()=>toast('Erro ao copiar.','err'));}
  else{toast('Erro ao copiar.','err');}
});

// dispara depois de tudo declarado
init();
